## Level 7 Checkpoint: The AI Code Review

You asked an AI to build a team member directory for a company intranet. The prompt you gave was:

> "Build a team directory that loads employees from an API, lets users search by name, and shows a detail card when you click on someone."

The AI generated the following component. Your job: review it using the checklist from Module 7.2, identify every issue, and write the prompt you would use to fix them.

Take your time. Read the code carefully. There are **five distinct issues** embedded in this component.

---

```tsx
import { useState, useEffect, useCallback, useMemo } from "react";

interface Employee {
  id: string;
  name: string;
  role: string;
  department: string;
  email: string;
  avatarUrl: string;
}

const TeamDirectory = () => {
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [filteredEmployees, setFilteredEmployees] = useState<Employee[]>([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedEmployee, setSelectedEmployee] = useState<Employee | null>(null);

  useEffect(() => {
    fetch("/api/employees")
      .then(res => res.json())
      .then(data => setEmployees(data));
  }, []);

  useEffect(() => {
    const filtered = employees.filter(emp =>
      emp.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
    setFilteredEmployees(filtered);
  }, [employees, searchTerm]);

  return (
    <div className="directory">
      <h1>Team Directory</h1>
      <input
        placeholder="Search employees..."
        value={searchTerm}
        onChange={e => setSearchTerm(e.target.value)}
      />

      <div className="employee-grid">
        {filteredEmployees.map((emp, index) => (
          <div
            key={index}
            className="employee-card"
            onClick={() => setSelectedEmployee(emp)}
          >
            <img src={emp.avatarUrl} />
            <h3>{emp.name}</h3>
            <p>{emp.role}</p>
            <p>{emp.department}</p>
          </div>
        ))}
      </div>

      {selectedEmployee && (
        <div className="detail-panel">
          <h2>{selectedEmployee.name}</h2>
          <p>{selectedEmployee.role}</p>
          <p>{selectedEmployee.department}</p>
          <p>{selectedEmployee.email}</p>
          <div onClick={() => setSelectedEmployee(null)} className="close-btn">
            X
          </div>
        </div>
      )}
    </div>
  );
};

export default TeamDirectory;
```

